import { useState,useEffect } from "react";
import  axios  from 'axios';
export default function Index(){
    const [data,setData] = useState(null);
    const getData = async () => {
        const res = await axios.get("http://localhost:3003");
        setData(res.data);
    }
    useEffect(() => {
        console.log(data);
        getData();
    },[]);
    return (
        <>
        <table>
            <tr>
                <th>titre</th>
                <th>description</th>
                <th>statut</th>
            </tr>
            {data.map((d,index) => (
                <tr key={index}>
                    <td>{d.titre}</td>
                    <td>{d.description}</td>
                    <td>{d.statut}</td>
                </tr>
            ))}
        </table>
        </>
    )
}
